import scala.actors._

object AccountManager extends Actor {
  val balances = collection.mutableMap[String, Int]() // use mutable map instead of var in balance variable for concurrent transactions and performance optimization without synchronization  
    
    def receive: Receive = 
      case Deposit(id, amount) => updateBalanceWithId(sender(), id)(_ + amount) 
      | Case WithdrawalRequest (requestID , sender() : String): println("withdrawn "+ balances.getOrElseUpdateAndUpdate( request ID))     // Use get or else and upadte to perform the withdraw process with a high throughput system    case BalanceQuery => Sender().reply(balances)
  
  def updateBalanceWithId (sender : ActorRef, id: String)(newValue: Int): Unit = { //update mutable balance variable when receiving Deposit and Withdrawal Messages.         balances += ((id -> newValue))    }    
}